#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <limits>

// The user's findLargest function is expected to be linked.
// For the purpose of this driver, we declare it extern.
extern int findLargest(const std::vector<int>& arr);

void run_test_case(const std::string& input_str, const std::string& expected_output) {
    std::stringstream ss_in(input_str);
    std::stringstream ss_out;

    int n;
    ss_in >> n;

    std::vector<int> arr;
    if (n > 0) {
        arr.resize(n);
        for (int i = 0; i < n; ++i) {
            ss_in >> arr[i];
        }
    }

    // Redirect std::cout
    std::streambuf* old_cout = std::cout.rdbuf(ss_out.rdbuf());

    if (n <= 0) {
        // Mimic the main function's empty array handling as per problem statement
        std::cout << "Array is empty." << std::endl;
    } else {
        int result = findLargest(arr);
        std::cout << result << std::endl;
    }

    // Restore std::cout
    std::cout.rdbuf(old_cout);

    std::string actual_output = ss_out.str();
    // Trim trailing newline for comparison
    if (!actual_output.empty() && actual_output.back() == '\n') {
        actual_output.pop_back();
    }

    std::cout << "Input: \"" << input_str << "\"" << std::endl;
    std::cout << "Expected: \"" << expected_output << "\"" << std::endl;
    std::cout << "Actual: \"" << actual_output << "\"" << std::endl;
    if (actual_output == expected_output) {
        std::cout << "Result: PASSED" << std::endl << std::endl;
    } else {
        std::cout << "Result: FAILED" << std::endl << std::endl;
    }
}

int main() {
    run_test_case("6\n10 5 20 15 25 8", "25");
    run_test_case("5\n-10 -5 -20 -15 -25", "-5");
    run_test_case("1\n42", "42");
    run_test_case("1\n-7", "-7");
    run_test_case("0\n", "Array is empty.");
    return 0;
}
